  audio_device_no_device(17),

  /// @brief 失败，当前设备不可用，需更换设备。
  ///
  audio_device_can_not_use(18),

  /// @brief 系统错误，设备初始化失败。
  ///
  audio_device_init_failed(19),

  /// @brief 系统错误，设备开启失败。
