/** {zh}
        * @detail keytype
* @brief SDK 与 RTC 服务器连接状态。
        */
enum ConnectionState {
  /// @brief 连接断开超过 12s，此时 SDK 会尝试自动重连。
  ///
  disconnected(0),

  /// @brief 首次请求建立连接，正在连接中。
  ///
  connecting(1),

  /// @brief 首次连接成功。
  ///
  connected(2),

  /// @brief 涵盖了以下情况： <br>
  ///        - 首次连接时，10 秒内未连接成功;
  ///        - 连接成功后，断连 10 秒。自动重连中。
  ///
  reconnecting(3),

  /// @brief 连接断开后，重连成功。
  ///
  reconnected(4),

  /// @brief 处于 `CONNECTION_STATE_DISCONNECTED` 状态超过 10 秒，且期间重连未成功。SDK 仍将继续尝试重连。
  ///
  lost(5),

  /// @brief 连接失败，服务端状态异常。SDK 不会自动重连，请重新进房，或联系技术支持。
  ///
  failed(6);

  final dynamic $value;
  const ConnectionState([this.$value]);
}

