/** {zh}
        * @detail keytype
* @brief 本地视频状态改变时的错误码
        */
enum LocalVideoStreamError {
  /// @brief 状态正常（本地视频状态改变正常时默认返回值）
  ///
  ok(0),

  /// @brief 本地视频流发布失败
  ///
  failure(1),

  /// @brief 没有权限启动本地视频采集设备
  ///
  deviceNoPermission(2),

  /// @brief 本地视频采集设备已被占用
  ///
  deviceBusy(3),

  /// @brief 本地视频采集设备不存在或已移除
  ///
  deviceNotFound(4),

  /// @brief 本地视频采集失败，建议检查采集设备是否正常工作
  ///
  captureFailure(5),

  /// @brief 本地视频编码失败
  ///
  encodeFailure(6),

  /// @brief 通话过程中本地视频采集设备被其他程序抢占，导致设备连接中断
  ///
  deviceDisconnected(7);

  final dynamic $value;
  const LocalVideoStreamError([this.$value]);
}

