* @brief 所属用户的媒体流网络质量。
        */
enum NetworkQuality {
  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量未知。
  ///
  NETWORK_QUALITY_UNKNOWN(0),

  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量极好。
  ///
  NETWORK_QUALITY_EXCELLENT(1),

  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量好。
  ///
  NETWORK_QUALITY_GOOD(2),

  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量较差但不影响沟通。
  ///
  NETWORK_QUALITY_POOR(3),

  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量差沟通不顺畅。
  ///
  NETWORK_QUALITY_BAD(4),

  /// @platform android
  /// @detail keytype
  /// @brief 媒体流网络质量非常差。
  ///
  NETWORK_QUALITY_VERY_BAD(5),

  /// @platform android
  /// @detail keytype
  /// @brief 网络连接断开，无法通话。网络可能由于 12s 内无应答、开启飞行模式、拔掉网线等原因断开。 <br>
  ///        更多网络状态信息参见 [连接状态提示](https://www.volcengine.com/docs/6348/95376)。
  ///
  NETWORK_QUALITY_DOWN(6),

  /// @platform ios
  /// @brief 网络质量未知。
  ///
  ByteRTCNetworkQualityUnknown(7),

  /// @platform ios
  /// @brief 网络质量极好。
  ///
  ByteRTCNetworkQualityExcellent(8),

  /// @platform ios
  /// @brief 主观感觉和 kNetworkQualityExcellent 差不多，但码率可能略低。
  ///
  ByteRTCNetworkQualityGood(9),

  /// @platform ios
  /// @brief 主观感受有瑕疵但不影响沟通。
  ///
  ByteRTCNetworkQualityPoor(10),

  /// @platform ios
  /// @brief 勉强能沟通但不顺畅。
  ///
  ByteRTCNetworkQualityBad(11),

  /// @platform ios
  /// @brief 网络质量非常差，基本不能沟通。
  ///
  ByteRTCNetworkQualityVeryBad(12),

  /// @platform ios
  /// @brief 网络连接断开，无法通话。网络可能由于 12s 内无应答、开启飞行模式、拔掉网线等原因断开。 <br>
  ///        更多网络状态信息参见 [连接状态提示](https://www.volcengine.com/docs/6348/95376)。
  ///
  ByteRTCNetworkQualityDown(13);

  final dynamic $value;
  const NetworkQuality([this.$value]);
}

