/** {zh}
        * @detail keytype
* @brief 本地音频流状态改变时的错误码。
        */
enum LocalAudioStreamError {
  /// @brief 本地音频状态正常
  ///
  ok(0),

  /// @brief 本地音频出错原因未知
  ///
  failure(1),

  /// @brief 没有权限启动本地音频录制设备
  ///
  deviceNoPermission(2),

  /// @platform ios
  /// @hidden currently not available
  /// @brief 本地音频录制设备已经在使用中
  /// @note 该错误码暂未使用
  ///
  deviceBusy(3),

  /// @brief 本地音频录制失败，建议你检查录制设备是否正常工作
  ///
  recordFailure(4),

  /// @brief 本地音频编码失败
  ///
  encodeFailure(5),

  /// @brief 没有可用的音频录制设备
  ///
  noRecordingDevice(6),

  /// @platform android
  /// @hidden currently not available
  /// @brief 本地音频录制设备已经在使用中
  /// @note 该错误码暂未使用
  ///
  LOCAL_AUDIO_STREAM_ERROR_DEVICE_BUSY(7);

  final dynamic $value;
  const LocalAudioStreamError([this.$value]);
}

